# Salt for key derivation (should be stored securely)
SALT = b'pharmacy-expense-tracker-salt'  # Change this to a random value in production

# Derive a secure key from a password (you can change this password)
def derive_key():
    password = b'secure-pharmacy-password-2025'  # Change this to a strong password
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=SALT,
        iterations=100_000,
    )
    return base64.urlsafe_b64encode(kdf.derive(password))

ENCRYPTION_KEY = derive_key()

# --- User Management and Authentication ---
def encrypt_users(data: str):
    # Use the same encryption as your main data
    from cryptography.fernet import Fernet
    key = derive_key()
    f = Fernet(key)
    with open(USERS_FILE_PATH, 'wb') as f_out:
        f_out.write(f.encrypt(data.encode()))

def decrypt_users() -> str:
    from cryptography.fernet import Fernet
    key = derive_key()
    f = Fernet(key)
    if not os.path.exists(USERS_FILE_PATH):
        return ''
    with open(USERS_FILE_PATH, 'rb') as f_in:
        return f.decrypt(f_in.read()).decode()


def load_users():
    try:
        data = decrypt_users()
        return json.loads(data) if data else []
    except Exception:
        return []

def save_users(users):
    encrypt_users(json.dumps(users))

def hash_pw(password):
    return bcrypt.hashpw(password.encode(), bcrypt.gensalt()).decode()

def check_pw(password, hashed):
    return bcrypt.checkpw(password.encode(), hashed.encode())

