# --- Login Dialog ---
class LoginDialog(QtWidgets.QDialog):
    def __init__(self):
        super().__init__()
        self.setWindowTitle('تسجيل الدخول')
        self.setModal(True)
        self.setFixedSize(300, 180)
        layout = QtWidgets.QVBoxLayout(self)
        # Username ComboBox
        self.userCombo = QtWidgets.QComboBox(self)
        self.userCombo.setEditable(False)
        users = load_users()
        usernames = [user['username'] for user in users]
        self.userCombo.addItems(usernames)

        self.passEdit = QtWidgets.QLineEdit(self)
        self.passEdit.setPlaceholderText('كلمة المرور')
        self.passEdit.setEchoMode(QtWidgets.QLineEdit.Password)
        self.loginBtn = QtWidgets.QPushButton('تسجيل الدخول', self)
        self.loginBtn.clicked.connect(self.login)
        layout.addWidget(QtWidgets.QLabel('اسم المستخدم:'))
        layout.addWidget(self.userCombo)
        layout.addWidget(QtWidgets.QLabel('كلمة المرور:'))
        layout.addWidget(self.passEdit)
        layout.addWidget(self.loginBtn)
        self.result = None
    def login(self):
        users = load_users()
        u = self.userCombo.currentText()
        p = self.passEdit.text()
        for user in users:
            if user['username'] == u and check_pw(p, user['password_hash']):
                self.result = user
                self.accept()
                return
        QtWidgets.QMessageBox.warning(self, 'فشل تسجيل الدخول', 'اسم المستخدم أو كلمة المرور غير صحيحة')

# --- User Management Dialog ---
class UserManagerDialog(QtWidgets.QDialog):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle('إدارة المستخدمين')
        self.setMinimumSize(400, 300)
        layout = QtWidgets.QVBoxLayout(self)
        self.table = QtWidgets.QTableWidget(self)
        self.table.setColumnCount(3)
        self.table.setHorizontalHeaderLabels(['اسم المستخدم', 'الدور', 'تغيير كلمة المرور'])
        layout.addWidget(self.table)
        self.addBtn = QtWidgets.QPushButton('إضافة مستخدم', self)
        self.addBtn.clicked.connect(self.add_user)
        layout.addWidget(self.addBtn)
        self.refresh()
    def refresh(self):
        users = load_users()
        self.table.setRowCount(len(users))
        current_admin = getattr(self.parent(), 'user', {'username': 'admin'})['username'] if self.parent() else 'admin'
        for i, user in enumerate(users):
            self.table.setItem(i, 0, QtWidgets.QTableWidgetItem(user['username']))
            self.table.setItem(i, 1, QtWidgets.QTableWidgetItem(user['role']))
            btn = QtWidgets.QPushButton('تغيير كلمة المرور', self)
            btn.clicked.connect(lambda _, u=user['username']: self.change_pw(u))
            self.table.setCellWidget(i, 2, btn)
            # Add Rename button if not self
            rename_btn = QtWidgets.QPushButton('إعادة التسمية', self)
            rename_btn.clicked.connect(lambda _, u=user['username']: self.rename_user(u))
            # Add Delete button if not self
            del_btn = QtWidgets.QPushButton('حذف', self)
            if user['username'] == current_admin:
                del_btn.setEnabled(False)
                del_btn.setToolTip('لا يمكن حذف المشرف الحالي')
            else:
                del_btn.clicked.connect(lambda _, u=user['username']: self.delete_user(u))
            # Add rename and delete buttons in new columns
            if self.table.columnCount() < 5:
                self.table.setColumnCount(5)
                self.table.setHorizontalHeaderLabels(['اسم المستخدم', 'الدور', 'تغيير كلمة المرور', 'إعادة التسمية', 'حذف'])
            self.table.setCellWidget(i, 3, rename_btn)
            self.table.setCellWidget(i, 4, del_btn)

    def rename_user(self, username):
        users = load_users()
        new_username, ok = QtWidgets.QInputDialog.getText(self, 'إعادة تسمية المستخدم', f'أدخل اسم المستخدم الجديد لـ {username}:')
        if not ok or not new_username:
            return
        if any(u['username'] == new_username for u in users):
            QtWidgets.QMessageBox.warning(self, 'موجود مسبقاً', 'اسم المستخدم موجود بالفعل')
            return
        for user in users:
            if user['username'] == username:
                user['username'] = new_username
        save_users(users)
        # Update parent dialog's user info if renaming current user
        parent = self.parent()
        if parent and hasattr(parent, 'user') and parent.user['username'] == username:
            parent.user['username'] = new_username
        self.refresh()

    def delete_user(self, username):
        reply = QtWidgets.QMessageBox.question(self, 'حذف المستخدم', f'هل أنت متأكد من حذف المستخدم "{username}"؟', QtWidgets.QMessageBox.Yes | QtWidgets.QMessageBox.No)
        if reply == QtWidgets.QMessageBox.Yes:
            users = load_users()
            users = [u for u in users if u['username'] != username]
            save_users(users)
            self.refresh()

    def add_user(self):
        u, ok = QtWidgets.QInputDialog.getText(self, 'إضافة مستخدم', 'اسم المستخدم:')
        if not ok or not u: return
        pw, ok = QtWidgets.QInputDialog.getText(self, 'إضافة مستخدم', 'كلمة المرور:', QtWidgets.QLineEdit.Password)
        if not ok or not pw: return
        role, ok = QtWidgets.QInputDialog.getItem(self, 'إضافة مستخدم', 'الدور:', ['user', 'admin'], 0, False)
        if not ok: return
        users = load_users()
        if any(x['username'] == u for x in users):
            QtWidgets.QMessageBox.warning(self, 'موجود مسبقاً', 'المستخدم موجود بالفعل')
            return
        users.append({'username': u, 'password_hash': hash_pw(pw), 'role': role})
        save_users(users)
        self.refresh()
    def change_pw(self, username):
        pw, ok = QtWidgets.QInputDialog.getText(self, 'تغيير كلمة المرور', f'كلمة المرور الجديدة لـ {username}:', QtWidgets.QLineEdit.Password)
        if not ok or not pw: return
        users = load_users()
        for user in users:
            if user['username'] == username:
                user['password_hash'] = hash_pw(pw)
        save_users(users)
        self.refresh()

# Salt for key derivation (should be stored securely)
SALT = b'pharmacy-expense-tracker-salt'  # Change this to a random value in production

# Derive a secure key from a password (you can change this password)
password = b'secure-pharmacy-password-2025'  # Change this to a strong password
kdf = PBKDF2HMAC(
    algorithm=hashes.SHA256(),
    length=32,
    salt=SALT,
    iterations=100000
)
ENCRYPTION_KEY = base64.urlsafe_b64encode(kdf.derive(password))

# Encryption/Decryption functions
def encrypt_data(data):
    """Encrypt data and save to file using Fernet encryption"""
    try:
        # Handle both StringIO objects and strings
        if hasattr(data, 'getvalue'):
            csv_data = data.getvalue()
        else:
            csv_data = data
        
        # Convert to bytes
        byte_data = csv_data.encode()
        
        # Create Fernet instance
        fernet = Fernet(ENCRYPTION_KEY)
        
        # Encrypt data
        encrypted = fernet.encrypt(byte_data)
        
        # Save to file
        with open(ENCRYPTED_FILE_PATH, 'wb') as f:
            f.write(encrypted)
    except Exception as e:
        print(f"Error encrypting data: {str(e)}")
        raise

def decrypt_data():
    """Decrypt data from file and return CSV string"""
    try:
        with open(ENCRYPTED_FILE_PATH, 'rb') as f:
            # Read encrypted data
            encrypted = f.read()
            
            # Create Fernet instance
            fernet = Fernet(ENCRYPTION_KEY)
            
            # Decrypt data
            decrypted = fernet.decrypt(encrypted)
            
            # Convert to string
            return decrypted.decode()
    except FileNotFoundError:
        return ""  # Return empty string if file not found
    except Exception as e:
        print(f"Error decrypting data: {str(e)}")
        raise

def safe_parse_payment_info(payment_info_str):
    """Safely parse payment info from a string, handling None or invalid JSON."""
    print(f"\n--- safe_parse_payment_info ---")
    print(f"Input payment_info_str: {payment_info_str}")
    print(f"Type of payment_info_str: {type(payment_info_str)}")
    
    # If it's already a dictionary, return it as is
    if isinstance(payment_info_str, dict):
        print("Input is already a dictionary, returning as is")
        return payment_info_str
        
    # If it's None or empty string, return empty dict
    if not payment_info_str:
        print("Input is empty, returning empty dict")
        return {}
        
    # If it's a string that looks like a timestamp, it's not valid payment info
    if isinstance(payment_info_str, str) and (len(payment_info_str) == 19 and ':' in payment_info_str and '-' in payment_info_str):
        print("Input appears to be a timestamp, returning empty dict")
        return {}
    
    # Try to parse as JSON
    try:
        if isinstance(payment_info_str, str):
            # Clean the string if it has extra quotes or backslashes
            cleaned_str = payment_info_str.strip().strip('"').replace('\"', '"')
            print(f"Cleaned payment info string: {cleaned_str}")
            result = json.loads(cleaned_str)
            print(f"Successfully parsed payment info: {result}")
            return result
        else:
            print(f"Input is not a string, returning empty dict")
            return {}
    except json.JSONDecodeError as e:
        print(f"Warning: Could not parse payment info as JSON: {e}")
        print(f"Problematic payment info: {payment_info_str}")
        return {}
    except Exception as e:
        print(f"Unexpected error parsing payment info: {e}")
        print(f"Payment info that caused error: {payment_info_str}")
        return {}

def get_outstanding_balance(provider):
    """Calculate the total outstanding balance for a specific provider."""
    try:
        csv_data = decrypt_data()
        if not csv_data:
            return 0.0
            
        from io import StringIO
        import csv
        reader = csv.DictReader(StringIO(csv_data))
        
        total_owed = 0.0
        for row in reader:
            if row.get('provider') == provider:
                payment_info = safe_parse_payment_info(row.get('payment_info'))
                total_owed += float(payment_info.get('net_owed', 0))
        return max(0.0, total_owed)  # Ensure non-negative
    except Exception as e:
        print(f"Error calculating outstanding balance: {e}")
        return 0.0

