        # Connect payment amount input to format as currency
        def format_currency():
            try:
                text = self.payment_amount_input.text().strip()
                if not text:
                    return
                
                # Remove any non-numeric characters except decimal point
                clean_text = ''.join(c for c in text if c.isdigit() or c == '.')
                
                # Ensure only two decimal places
                if '.' in clean_text:
                    parts = clean_text.split('.')
                    if len(parts[0]) > 10:  # Limit to 10 digits before decimal
                        parts[0] = parts[0][:10]
                    if len(parts) > 1 and len(parts[1]) > 2:  # Limit to 2 decimal places
                        parts[1] = parts[1][:2]
                    clean_text = '.'.join(parts)
                
                # Format as currency
                try:
                    value = float(clean_text)
                    if value < 0:
                        value = 0.0
                    # Only update if the text actually needs to be reformatted
                    current_text = f"{value:.2f}"
                    if self.payment_amount_input.text() != current_text:
                        self.payment_amount_input.setText(current_text)
                except ValueError:
                    pass
                    
            except Exception as e:
                print(f"Error formatting currency: {e}")
        
        # Connect the formatting function to editingFinished signal
