        # Update summary function
        def update_summary(filtered_data=None):
            if filtered_data is None:
                filtered_data = data
                
            total_purchases = 0.0
            total_returned = 0.0
            total_paid = 0.0
            total_net_owed = 0.0
            
            for item in filtered_data:
                try:
                    # Basic amounts
                    amount = float(item.get('amount', 0) or 0)
                    returned = float(item.get('amount_returned', 0) or 0)
                    net_amount = amount - returned
                    
                    # Add to totals
                    total_purchases += amount
                    total_returned += returned
                    
                    # Payment info - use our safe parsing function
                    payment_info = safe_parse_payment_info(item.get('payment_info', '{}'))
                    payment_type = payment_info.get('type', 'cash').lower()
                    
                    try:
                        if payment_type == 'partial':
                            # For partial payments, use the stored values from payment_info
                            amount_paid = float(payment_info.get('amount_paid', 0) or 0)
                            net_owed = float(payment_info.get('net_owed', net_amount) or net_amount)
                            total_paid += amount_paid
                            total_net_owed += net_owed
                            
                        elif payment_type == 'debt':
                            # For debt, amount paid is 0 and net owed is the full amount
                            total_paid += 0.0
                            total_net_owed += net_amount
                            
                        else:  # cash
                            # For cash, amount paid is the full amount and net owed is 0
                            total_paid += net_amount
                            total_net_owed += 0.0
                            
                    except (ValueError, TypeError) as e:
                        print(f"Error processing payment info for summary: {e}")
                        # Default to cash payment on error
                        total_paid += net_amount
                        
                except Exception as e:
                    print(f"Error processing item for summary: {e}")
                    continue
            
            # Update the summary labels with the calculated values
            self.total_purchases_label.setText(f"إجمالي المشتريات: {total_purchases:,.2f}")
            self.total_returned_label.setText(f"إجمالي المرتجع: {total_returned:,.2f}")
            self.total_owed_label.setText(f"إجمالي المستحق: {total_net_owed:,.2f}")
            
            # Update net owed label if it exists
            if hasattr(self, 'net_owed_label'):
                self.net_owed_label.setText(f"باقي المديونية للشركة {total_net_owed:,.2f}")
            
            # Debug output
            print(f"Summary - Purchases: {total_purchases:,.2f}, Returned: {total_returned:,.2f}, Paid: {total_paid:,.2f}, Owed: {total_net_owed:,.2f}")
            
            return {
                'total_purchases': total_purchases,
                'total_returned': total_returned,
                'total_paid': total_paid,
                'total_net_owed': total_net_owed
            }
        
        # Initial summary update
        update_summary()
        
